-- p2502 Iltutmish
UPDATE personalities SET slug='iltutmish', title='Sultan', gender='Male', birth_year=NULL, death_year=1236, birth_text='c. 1180 CE', death_text='April 1236 CE', categories=ARRAY['Ruler','Administrator','Military']::TEXT[], civilization='Delhi Sultanate', historical_period='Medieval India', dynasty='Mamluk Dynasty', kingdom='Delhi Sultanate', religion='Islam', occupation=ARRAY['Sultan','Administrator']::TEXT[], birthplace='Central Asia', death_place='Delhi', region='North India', present_state='Delhi', present_country='India', short_description='Iltutmish was the third Sultan of Delhi who consolidated the Delhi Sultanate, shifted the capital from Lahore to Delhi, completed the Qutb Minar, and introduced the silver tanka currency system during his reign from 1211 to 1236.', famous_for='Considered the real founder of the Delhi Sultanate. Completed the Qutb Minar and introduced the first purely Islamic coinage in India.', achievements=ARRAY['Consolidated the Delhi Sultanate as an independent kingdom','Shifted capital from Lahore to Delhi','Completed construction of Qutb Minar','Introduced silver tanka and copper dirham currency','Received investiture from Abbasid Caliph of Baghdad']::TEXT[], notable_works=ARRAY['Qutb Minar (completion)']::TEXT[], notable_titles=ARRAY['Sultan of Delhi','Shams-ud-din']::TEXT[], active_start_year=1211, active_end_year=1236, century='13th century CE', timeline_order=31, father='Ilam Khan', mother=NULL, spouse=NULL, children=ARRAY['Razia Sultana','Ruknuddin Firuz','Muizuddin Bahram']::TEXT[], teacher=ARRAY[]::TEXT[], students=ARRAY[]::TEXT[], predecessor='Aram Shah', successor='Ruknuddin Firuz', contemporaries=ARRAY['Genghis Khan']::TEXT[], related_people=ARRAY['Qutb-ud-din Aibak','Razia Sultana']::TEXT[], related_events=ARRAY[]::TEXT[], related_dynasties=ARRAY['Mamluk Dynasty']::TEXT[], related_kingdoms=ARRAY['Delhi Sultanate']::TEXT[], wikipedia_url='https://en.wikipedia.org/wiki/Iltutmish', keywords=ARRAY['Iltutmish','Delhi Sultanate','Ma