UPDATE personalities SET slug='razia-sultana', title='Sultana', gender='Female', birth_year=1205, death_year=1240, birth_text='c. 1205 CE', death_text='1240 CE', categories=ARRAY['Ruler','Pioneer']::TEXT[], civilization='Delhi Sultanate', historical_period='Medieval India', dynasty='Mamluk Dynasty', kingdom='Delhi Sultanate', religion='Islam', occupation=ARRAY['Sultana']::TEXT[], birthplace='Budaun', death_place='Kaithal', region='North India', present_state='Haryana', present_country='India', short_description='Razia Sultana was the first and only female ruler of the Delhi Sultanate, reigning from 1236 to 1240. She broke gender conventions by adopting masculine attire, riding elephants, and leading her army.', famous_for='First and only female ruler of the Delhi Sultanate. She championed meritocracy over birth and adopted the title Sultan rather than Sultana.', achievements=ARRAY['First female ruler of the Delhi Sultanate','Adopted masculine attire and led armies in person','Issued coins in her own name','Championed meritocracy over noble birth']::TEXT[], notable_works=NULL, notable_titles=ARRAY['Sultan of Delhi','Jalalat-ud-din Razia']::TEXT[], active_start_year=1236, active_end_year=1240, century='13th century CE', timeline_order=32, father='Iltutmish', mother=NULL, spouse=ARRAY['Jamal-ud-Din Yaqut','Ikhtiyaruddin Altunia']::TEXT[], children=NULL, teacher=ARRAY[]::TEXT[], students=ARRAY[]::TEXT[], predecessor='Iltutmish', successor='Muizuddin Bahram', contemporaries=ARRAY[]::TEXT[], related_people=ARRAY['Iltutmish','Ruknuddin Firuz']::TEXT[], related_events=ARRAY[]::TEXT[], related_dynasties=ARRAY['Mamluk Dynasty']::TEXT[], related_kingdoms=ARRAY['Delhi Sultanate']::TEXT[], wikipedia_url='https://en.wikipedia.org/wiki/Razia_Sultana', keywords=ARRAY['Razia Sultana','Delhi Sultanate','Mamluk Dynasty','female ruler','Iltutmish','first woman ruler']::TEXT[], search_aliases=ARRAY['Razia Begum','Sultana Razia']::TEXT[], meta_description='Razia Sultana (r. 1236-1240) wa