UPDATE personalities SET slug='balban', title='Sultan', gender='Male', birth_year=NULL, death_year=1287, birth_text='c. 1200 CE', death_text='1287 CE', categories=ARRAY['Ruler','Administrator','Military']::TEXT[], civilization='Delhi Sultanate', historical_period='Medieval India', dynasty='Mamluk Dynasty', kingdom='Delhi Sultanate', religion='Islam', occupation=ARRAY['Sultan','Administrator']::TEXT[], birthplace='Central Asia', death_place='Delhi', region='North India', present_state='Delhi', present_country='India', short_description='Ghiyasuddin Balban was a Turkic slave who became Sultan of Delhi from 1266 to 1287. He strengthened the sultanate through strict administration, introduced Persian court customs of sijda and paibos, and established the theory of divine right of kingship.', famous_for='Introduced Persian court customs of sijda (prostration) and paibos (kissing the king''s feet). Broke the power of the Chahalgani (Group of Forty) nobles.', achievements=ARRAY['Broke the power of the Chahalgani nobles','Introduced sijda and paibos court customs','Established the theory of divine right of kingship','Reorganized the military with a strong spy network','Defended against Mongol invasions']::TEXT[], notable_works=NULL, notable_titles=ARRAY['Sultan of Delhi','Ghiyas-ud-din Balban','Ulugh Khan']::TEXT[], active_start_year=1246, active_end_year=1287, century='13th century CE', timeline_order=33, father=NULL, mother=NULL, spouse=NULL, children=ARRAY['Bughra Khan','Muhammad Khan']::TEXT[], teacher=ARRAY[]::TEXT[], students=ARRAY[]::TEXT[], predecessor='Nasiruddin Mahmud', successor='Muizuddin Kaiqubad', contemporaries=ARRAY['Hulagu Khan']::TEXT[], related_people=ARRAY['Iltutmish','Nasiruddin Mahmud']::TEXT[], related_events=ARRAY[]::TEXT[], related_dynasties=ARRAY['Mamluk Dynasty']::TEXT[], related_kingdoms=ARRAY['Delhi Sultanate']::TEXT[], wikipedia_url='https://en.wikipedia.org/wiki/Balban', keywords=ARRAY['Balban','Delhi Sultanate','Mamluk Dynasty','sijda','paibos','divine right','Chahalgani','Mongol invasions']::TEXT[], search_aliases=ARRAY['Ghiyasuddin Balban','Ulugh Khan']::TEXT[], meta_description='Balban (r. 1266-1287) strengthened the Delhi Sultanate with strict administration, Persian court customs, and the theory of divine kingship.', verified=TRUE, featured=FALSE, updated_at=NOW() WHERE id='p2504';

